import React, { useState } from 'react';

export default function AnnouncementsPage({ announcements, onAdd, error }) {
    const [newAnnouncement, setNewAnnouncement] = useState({ name: '', description: '' });

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setNewAnnouncement(prev => ({ ...prev, [name]: value }));
    };

    const add = () => onAdd(newAnnouncement).then(ok => ok && setNewAnnouncement({ name: '', description: '' }));

    return (
        <div className="container main">
            <div className="section">
                <h1 className="pageTitle">Announcements</h1>
                {error ? <div className="error">{error}</div> : null}

                <div className="announceForm">
                    <input className="input" type="text" name="name" placeholder="Title" value={newAnnouncement.name} onChange={handleInputChange} />
                    <input className="input" type="text" name="description" placeholder="Details" value={newAnnouncement.description} onChange={handleInputChange} />
                    <button className="button" onClick={add}>
                        Add
                    </button>
                </div>

                {announcements?.length ? (
                    <ul className="list">
                        {announcements
                            .slice()
                            .reverse()
                            .map(a => (
                                <li key={a.id} className="listItem">
                                    <div className="listTitle">{a.name}</div>
                                    <div className="listText">{a.description}</div>
                                </li>
                            ))}
                    </ul>
                ) : (
                    <p className="muted">No announcements yet.</p>
                )}
            </div>
        </div>
    );
}
